// MARK: - EncodingGuardTests

struct EncodingGuardTests {

    // MARK: Happy Path

    @Test func defaultMaxBytesIsTenMegabytes() {
        #expect(EncodingGuard.defaultMaxBytes == 10 * 1024 * 1024)
    }

    @Test func validUTF8FileReturnsUTF8() throws {
        let url = try writeTempFile(content: "Hello, world!", name: "eg_utf8.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        let enc = try EncodingGuard.validate(url)
        #expect(enc == .utf8)
    }

    @Test func emptyFileReturnsUTF8() throws {
        let url = try writeTempFile(content: "", name: "eg_empty.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        let enc = try EncodingGuard.validate(url)
        #expect(enc == .utf8)
    }

    @Test func fileSizeAtExactLimitSucceeds() throws {
        let content = String(repeating: "x", count: 50)
        let url = try writeTempFile(content: content, name: "eg_exact.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        let enc = try EncodingGuard.validate(url, maxBytes: 50)
        #expect(enc == .utf8)
    }

    // MARK: Edge Cases

    @Test func lowNullRatioPassesBinaryCheck() throws {
        // 1 null in ~14 bytes ≈ 7% — below the 15% rejection threshold.
        var data = Data("Hello, world!".utf8)
        data.append(0x00)
        let url = FileManager.default.temporaryDirectory.appendingPathComponent("eg_lownull.txt")
        try data.write(to: url)
        defer { try? FileManager.default.removeItem(at: url) }
        let enc = try EncodingGuard.validate(url)
        #expect(enc == .utf8)
    }

    @Test func fileSizeOneByteOverLimitThrows() throws {
        let url = try writeTempFile(content: String(repeating: "x", count: 51), name: "eg_over.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        #expect(throws: EncodingGuard.Failure.self) {
            try EncodingGuard.validate(url, maxBytes: 50)
        }
    }

    // MARK: Error Conditions

    @Test func oversizedFileThrowsFileTooLarge() throws {
        let url = try writeTempFile(content: String(repeating: "a", count: 100), name: "eg_big.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        #expect(throws: EncodingGuard.Failure.self) {
            try EncodingGuard.validate(url, maxBytes: 10)
        }
    }

    @Test func binaryDataThrowsBinaryOrUnreadable() throws {
        let nullBytes = Data(repeating: 0x00, count: 200)
        let url = FileManager.default.temporaryDirectory.appendingPathComponent("eg_binary.bin")
        try nullBytes.write(to: url)
        defer { try? FileManager.default.removeItem(at: url) }
        #expect(throws: EncodingGuard.Failure.self) {
            try EncodingGuard.validate(url)
        }
    }

    @Test func fileTooLargeErrorCarriesCorrectURL() throws {
        let url = try writeTempFile(content: "abc", name: "eg_urlcheck.txt")
        defer { try? FileManager.default.removeItem(at: url) }
        do {
            _ = try EncodingGuard.validate(url, maxBytes: 1)
            Issue.record("Expected EncodingGuard.Failure.fileTooLarge to be thrown")
        } catch EncodingGuard.Failure.fileTooLarge(let errURL, _, _) {
            #expect(errURL.lastPathComponent == url.lastPathComponent)
        } catch {
            Issue.record("Unexpected error type: \(error)")
        }
    }
}

