// MARK: - ImageToASCIIConverterTests

@MainActor
struct ImageToASCIIConverterTests {

    // MARK: Happy Path — RampStyle

    @Test func blockRampStartsWithDarkestCharacter() {
        #expect(ImageToASCIIConverter.RampStyle.block.characters.first == "@")
    }

    @Test func minimalRampHasFewerCharsThanBlock() {
        let block = ImageToASCIIConverter.RampStyle.block.characters.count
        let minimal = ImageToASCIIConverter.RampStyle.minimal.characters.count
        #expect(minimal < block)
    }

    @Test func allRampStylesEnumeratedAsCases() {
        #expect(ImageToASCIIConverter.RampStyle.allCases.count == 3)
    }

    @Test func brailleRampEndsWithSpace() {
        #expect(ImageToASCIIConverter.RampStyle.braille.characters.last == " ")
    }

    // MARK: Happy Path — convert

    @Test func convertProducesExpectedRowCount() {
        // Square image → aspect ratio 1.0 → height = width / 2 = 5 rows for width 10
        let image = makeSolidImage(color: .white, size: CGSize(width: 10, height: 10))
        let rows = ImageToASCIIConverter.convert(image, width: 10, invert: false, style: .block)
            .components(separatedBy: "\n")
        #expect(rows.count == 5)
    }

    @Test func convertProducesExpectedColumnCount() {
        let image = makeSolidImage(color: .white, size: CGSize(width: 20, height: 20))
        let firstRow =
            ImageToASCIIConverter.convert(image, width: 20, invert: false, style: .block)
            .components(separatedBy: "\n")
            .first ?? ""
        #expect(firstRow.count == 20)
    }

    @Test func convertOnlyUsesCharactersFromActiveRamp() {
        let image = makeSolidImage(color: .gray, size: CGSize(width: 8, height: 8))
        let output = ImageToASCIIConverter.convert(image, width: 8, invert: false, style: .minimal)
        let validChars = Set(ImageToASCIIConverter.RampStyle.minimal.characters).union(["\n"])
        for ch in output {
            #expect(validChars.contains(ch))
        }
    }

    // MARK: Edge Cases

    @Test func invertProducesDifferentOutputThanNonInvert() {
        // White image maps to lightest char normally, darkest char when inverted.
        let image = makeSolidImage(color: .white, size: CGSize(width: 4, height: 4))
        let normal = ImageToASCIIConverter.convert(image, width: 4, invert: false, style: .block)
        let inverted = ImageToASCIIConverter.convert(image, width: 4, invert: true, style: .block)
        #expect(normal != inverted)
    }
}

// MARK: - BlockCompletionTests

@MainActor
struct BlockCompletionTests {

    // MARK: Happy Path

    @Test func applyInsertsFrameReplacingPattern() {
        let bc = BlockCompletion()
        bc.stage(
            BlockCompletion.Payload(pattern: "+--", frame: "+---+\n|   |\n+---+", preview: "+---+"))
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "+--"))
        tv.setSelectedRange(NSRange(location: 3, length: 0))
        bc.apply(to: tv)
        #expect(tv.textStorage?.string == "+---+\n|   |\n+---+")
    }

    @Test func discardPreventsApply() {
        let bc = BlockCompletion()
        bc.stage(BlockCompletion.Payload(pattern: "+--", frame: "FRAME", preview: "preview"))
        bc.discard()
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "+--"))
        tv.setSelectedRange(NSRange(location: 3, length: 0))
        bc.apply(to: tv)
        #expect(tv.textStorage?.string == "+--")
    }

    @Test func applyWithNoStagedPayloadIsNoOp() {
        let bc = BlockCompletion()
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "hello"))
        tv.setSelectedRange(NSRange(location: 5, length: 0))
        bc.apply(to: tv)
        #expect(tv.textStorage?.string == "hello")
    }

    // MARK: Edge Cases

    @Test func applyWhenPatternAbsentIsNoOp() {
        let bc = BlockCompletion()
        bc.stage(BlockCompletion.Payload(pattern: "+--", frame: "FRAME", preview: "preview"))
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "hello"))
        tv.setSelectedRange(NSRange(location: 5, length: 0))
        bc.apply(to: tv)
        #expect(tv.textStorage?.string == "hello")
    }

    @Test func applyConsumesStagedPayloadSoSecondApplyIsNoOp() {
        let bc = BlockCompletion()
        bc.stage(BlockCompletion.Payload(pattern: "+--", frame: "BOX", preview: "preview"))
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "+--"))
        tv.setSelectedRange(NSRange(location: 3, length: 0))
        bc.apply(to: tv)  // applies, clears staged
        tv.textStorage?.setAttributedString(NSAttributedString(string: "+--"))
        tv.setSelectedRange(NSRange(location: 3, length: 0))
        bc.apply(to: tv)  // second apply — staged is nil, no-op
        #expect(tv.textStorage?.string == "+--")
    }
}

// MARK: - SearchControllerTests

@MainActor
struct SearchControllerTests {

    // MARK: Happy Path

    @Test func searchFindsAllMatches() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "cat bat cat"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "cat"
        sc.search()
        #expect(sc.matchRanges.count == 2)
    }

    @Test func searchIsCaseInsensitive() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hello HELLO hello"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "hello"
        sc.search()
        #expect(sc.matchRanges.count == 3)
    }

    @Test func nextMatchAdvancesIndex() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "a a a"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "a"
        sc.search()
        sc.nextMatch()
        #expect(sc.currentMatchIndex == 1)
    }

    @Test func nextMatchWrapsAroundToZero() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "a a"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "a"
        sc.search()
        sc.nextMatch()
        sc.nextMatch()
        #expect(sc.currentMatchIndex == 0)
    }

    @Test func previousMatchWrapsAroundToLast() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "a a a"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "a"
        sc.search()
        sc.previousMatch()
        #expect(sc.currentMatchIndex == 2)
    }

    @Test func replaceCurrentReplacesFirstMatch() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "cat cat"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "cat"
        sc.replaceTerm = "dog"
        sc.search()
        sc.replaceCurrent()
        #expect(tv.textStorage?.string.hasPrefix("dog") == true)
    }

    @Test func replaceAllReplacesEveryOccurrence() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "cat cat cat"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = "cat"
        sc.replaceTerm = "dog"
        sc.replaceAll()
        #expect(tv.textStorage?.string == "dog dog dog")
    }

    // MARK: Edge Cases

    @Test func emptySearchTermProducesNoMatches() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "hello"))
        let sc = SearchController(textView: tv)
        sc.searchTerm = ""
        sc.search()
        #expect(sc.matchRanges.isEmpty)
    }
}

// MARK: - GhostTextOverlayTests

@MainActor
struct GhostTextOverlayTests {

    // MARK: Happy Path

    @Test func showMakesOverlayVisible() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hello"))
        tv.setSelectedRange(NSRange(location: 5, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show(" world")
        #expect(overlay.isVisible)
    }

    @Test func clearMakesOverlayInvisible() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hello"))
        tv.setSelectedRange(NSRange(location: 5, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show(" world")
        overlay.clear()
        #expect(!overlay.isVisible)
    }

    @Test func showInsertsCharactersAtCursor() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hi"))
        tv.setSelectedRange(NSRange(location: 2, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show("!")
        #expect(tv.textStorage?.length == 3)
    }

    @Test func clearRestoresOriginalLength() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hi"))
        tv.setSelectedRange(NSRange(location: 2, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show("!!")
        overlay.clear()
        #expect(tv.textStorage?.length == 2)
    }

    @Test func acceptAdvancesCursorPastGhostText() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hi"))
        tv.setSelectedRange(NSRange(location: 2, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show("!!")
        overlay.accept()
        #expect(tv.selectedRange().location == 4)
    }

    // MARK: Edge Cases

    @Test func showEmptySuggestionDoesNotBecomeVisible() {
        let tv = NSTextView(frame: CGRect(x: 0, y: 0, width: 400, height: 300))
        tv.textStorage?.setAttributedString(NSAttributedString(string: "Hi"))
        tv.setSelectedRange(NSRange(location: 2, length: 0))
        let overlay = GhostTextOverlay(textView: tv)
        overlay.show("")
        #expect(!overlay.isVisible)
    }
}

